import React, {useEffect, useRef, useState} from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    // const didMountRef = useRef(false);
    // useEffect( () => {
    //     if (didMountRef.current) {
    //
    //         document.querySelectorAll("html body .styles_navLinks__38tON ul li")[0].addEventListener('click', e=>{
    //             window.scrollTo({
    //                 top: 400,
    //                 behavior: 'smooth',
    //             });
    //             console.log("HOME");
    //         });
    //     } else
    //     {
    //         didMountRef.current = true;
    //         console.log("HERE")
    //     }
    //
    //
    // });
    const [isClicked,SetClick] = useState(false);
    useEffect(() => {
        // var children = document.querySelectorAll(".styles_navLinks__38tON ul li a");
        if(isClicked)
        {
            document.querySelectorAll("html body .styles_navLinks__38tON ul li a").forEach(function (child) {
                // var a = document.getElementById(child);
                child.setAttribute("href", "#aboutme");
                child.addEventListener('click', (e) => {

                    window.scrollTo({
                        top: 400,
                        behavior: 'smooth',
                    });
                    }
                );

            });
        }

    });
    return (
        <div onClick={()=>SetClick(true)}>
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'

            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "aboutme" },
                { name: "PROJECT", to: "project" },
                { name: "CONTACT", to: "contact" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}

        />
        </div>
    )
};
export default Navbar;
